import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"Instalando Java no Windows","description":"Um guia passo a passo de como instalar Java no Windows.","frontmatter":{"title":"Instalando Java no Windows","description":"Um guia passo a passo de como instalar Java no Windows.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"pt_br/1.21.8/players/installing-java/windows.md","filePath":"versions/1.21.8/translated/pt_br/players/installing-java/windows.md","lastUpdated":1760721669000}`);var l={name:`pt_br/1.21.8/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalando Java no Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalando Java no Windows”">​</a></h1><p>Este guia o orientará na instalação do Java 17 no Windows.</p><p>O Launcher do Minecraft vem com sua própria instalação do Java, portanto esta seção só é relevante se você quiser usar o instalador baseado em <code>.jar</code> do Fabric ou se quiser usar o <code>.jar</code> do Servidor do Minecraft.</p><h2 id="_1-verificar-se-o-java-ja-esta-instalado" tabindex="-1">1. Verificar Se o Java Já Está Instalado <a class="header-anchor" href="#_1-verificar-se-o-java-ja-esta-instalado" aria-label="Permalink to “1. Verificar Se o Java Já Está Instalado”">​</a></h2><p>Para verificar se o Java já está instalado, você deve primeiro abrir o prompt de comando.</p><p>Você pode fazer isso apertando <kbd>Win</kbd>+<kbd>R</kbd> e digitando <code>cmd.exe</code> na janela aberta.</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Caixa de diálogo Executar do Windows com &quot;cmd.exe&quot; na barra de execução" loading="lazy"></p><p>Após abrir o prompt de comando, digite <code>java -version</code> e pressione <kbd>Enter</kbd>.</p><p>Se o comando for executado com êxito, você verá algo parecido com isto. Se o comando falhar, prossiga para o próximo passo.</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Prompt de comando com &quot;java -version&quot; digitado" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Para usar a maioria das versões modernas do Minecraft, você precisará ter pelo menos o Java 17 instalado. Se este comando exibir uma versão inferior a 17, será necessário atualizar sua instalação do Java atual.</p></div><h2 id="_2-baixar-o-instalador-do-java-17" tabindex="-1">2. Baixar o Instalador do Java 17 <a class="header-anchor" href="#_2-baixar-o-instalador-do-java-17" aria-label="Permalink to “2. Baixar o Instalador do Java 17”">​</a></h2><p>Para instalar o Java 17, você precisará baixar o instalador pelo <a href="https://adoptium.net/en-GB/temurin/releases/?os=windows&amp;package=jdk&amp;version=17" target="_blank" rel="noreferrer">Adoptium</a>.</p><p>Você deverá baixar a versão <code>Windows Installer (.msi)</code>:</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Página de download do Adoptium com Windows Installer (.msi) destacado" loading="lazy"></p><p>Você deverá escolher &#39;x86&#39; se tiver um sistema operacional 32-bit, ou &#39;x64&#39; se tiver um sistema operacional 64-bit.</p><p>A maioria dos computadores modernos terão um sistema operacional 64-bit. Em caso de dúvida, tente usar o download 64-bit.</p><h2 id="_3-executar-o-instalador" tabindex="-1">3. Executar o Instalador! <a class="header-anchor" href="#_3-executar-o-instalador" aria-label="Permalink to “3. Executar o Instalador!”">​</a></h2><p>Siga os passos do instalador para instalar o Java 17. Ao chegar nesta página, você deve definir os seguintes recursos como &quot;Todo o recurso será instalado no disco rígido local&quot;:</p><ul><li><code>Set JAVA_HOME environment variable</code> - Isso será adicionado ou seu PATH.</li><li><code>JavaSoft (Oracle) registry keys</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Instalador do Java 17 com &quot;Set JAVA_HOME variable&quot; e &quot;JavaSoft (Oracle) registry keys&quot; destacados" loading="lazy"></p><p>Assim que fizer isto, clique em &#39;Next&#39; e continue com a instalação.</p><h2 id="_4-verificar-se-o-java-17-esta-instalado" tabindex="-1">4. Verificar se o Java 17 está instalado <a class="header-anchor" href="#_4-verificar-se-o-java-17-esta-instalado" aria-label="Permalink to “4. Verificar se o Java 17 está instalado”">​</a></h2><p>Assim que a instalação terminar, você pode verificar se o Java 17 está instalado abrindo o prompt de comando novamente e digitando <code>java -version</code>.</p><p>Se o comando for executado com êxito, você verá algo como mostrado anteriormente onde a versão do Java é exibida:</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Prompt de comando com &quot;java -version&quot; digitado" loading="lazy"></p><hr><p>Se você encontrar algum problema, sinta-se à vontade para pedir ajuda no <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord do Fabric</a> no canal <code>#player-support</code>.</p>`,28)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};